25	using BicepFunction = Azure.Provisioning.Expressions.BicepFunction;
26	using BicepIdentifierExpression = Azure.Provisioning.Expressions.IdentifierExpression;
27	
28	namespace Azure.Generator.Provisioning.Providers
29	{
30	    /// <summary>
31	    /// Generates a ProvisionableResource subclass from an InputModelType + ArmResourceMetadata.
32	    /// Flattens the ARM "properties" bag, includes system properties from the base model chain,
33	    /// and generates ResourceVersions, FromExisting, and the resource constructor.
34	    /// </summary>
35	    internal class ProvisioningResourceProvider : ModelProvider, IProvisioningPropertyInfo
36	    {
37	        // System properties that should always be output-only
38	        private static readonly HashSet<string> OutputOnlyProperties = new(StringComparer.OrdinalIgnoreCase)
39	        {
40	            "id", "systemData", "type"
41	        };
42	
43	        // System properties that should always be required, even when marked readOnly (path parameters)
44	        private static readonly HashSet<string> RequiredInputProperties = new(StringComparer.OrdinalIgnoreCase)
45	        {
46	            "name"
47	        };
48	
49	        // Properties to skip entirely (type is implied by the resource type)
50	        private static readonly HashSet<string> SkipProperties = new(StringComparer.OrdinalIgnoreCase)
51	        {
52	            "type"
53	        };
54	
55	        private readonly InputModelType _inputModel;
56	        private readonly ArmResourceMetadata? _resourceMetadata;
57	        private readonly string? _defaultApiVersion;
58	        /// <summary>
59	        /// All collected properties for the resource, including flattened and inherited ones,
60	        /// with their resolved isOutput/isRequired/bicepPath metadata.
61	        /// Used to build the C# Properties, Fields, and DefineProvisionableProperties() method.
62	        /// </summary>
63	        private readonly List<ResourcePropertyInfo> _allProperties;
64	        /// <summary>
65	        /// Lookup from InputModelProperty to ResourcePropertyInfo for O(1) access in
66	        /// <see cref="IProvisioningPropertyInfo.GetProvisioningPropertyInfo"/>.
67	        /// </summary>
68	        private readonly Dictionary<InputModelProperty, ResourcePropertyInfo> _propertyLookup;
69	        /// <summary>
70	        /// Serialized property names that are writable in the create/update request body model.
71	        /// When the resource model is output-only (e.g., a ProxyResource with a separate create body),
72	        /// its properties may be marked readOnly even though the create body accepts them as input.
73	        /// This set is used during <see cref="_allProperties"/> construction to avoid incorrectly
74	        /// marking such properties as output-only.
75	        /// </summary>
76	        private readonly HashSet<string> _createBodyWritableProperties;
77	
78	        private FieldProvider? _parentField;
79	        private PropertyProvider? _parentProperty;
80	        private CSharpType? _parentType;
81	
82	        /// <summary>
83	        /// Gets the resource metadata, if this is a base resource type.
84	        /// </summary>
85	        internal ArmResourceMetadata? ResourceMetadata => _resourceMetadata;
86	
87	        /// <summary>
88	        /// Gets the parent resource's CSharpType via the output library, or null for top-level resources.
89	        /// </summary>
90	        private CSharpType? ParentResourceType
91	            => _resourceMetadata?.ParentResourceId is { } parentId
92	                ? ProvisioningGenerator.Instance.OutputLibrary.GetResourceByIdPattern(parentId)?.Type
93	                : null;
94	
95	        /// <inheritdoc/>
96	        ProvisioningPropertyInfo? IProvisioningPropertyInfo.GetProvisioningPropertyInfo(InputModelProperty inputProp)
97	        {
98	            if (!_propertyLookup.TryGetValue(inputProp, out var propInfo))
99	                return null;
100	            return new ProvisioningPropertyInfo(
101	                propInfo.PropertyName,
102	                propInfo.IsOutput,
103	                propInfo.IsRequired,
104	                propInfo.BicepPath,
105	                propInfo.DefaultValue,
106	                propInfo.TypeOverride);
107	        }
108	
109	        /// <summary>
110	        /// Constructor for base resource types (with metadata from ARM provider schema).
111	        /// </summary>
112	        public ProvisioningResourceProvider(InputModelType inputModel, ArmResourceMetadata metadata)
113	            : base(inputModel)
114	        {
115	            _inputModel = inputModel;
116	            _resourceMetadata = metadata;
117	            _defaultApiVersion = metadata.ApiVersions.Count > 0
118	                ? metadata.ApiVersions.Last()
119	                : null;
120	            _createBodyWritableProperties = BuildCreateBodyWritableProperties();
121	            _allProperties = CollectAllProperties();
122	            _propertyLookup = _allProperties.ToDictionary(p => p.Property);
123	        }
124	
125	        /// <summary>
126	        /// Constructor for derived discriminated resource types (no metadata, inherits from base resource).
127	        /// </summary>
128	        internal ProvisioningResourceProvider(InputModelType inputModel)
129	            : base(inputModel)
130	        {
131	            _inputModel = inputModel;
132	            _resourceMetadata = null;
133	            _defaultApiVersion = null;
134	            _createBodyWritableProperties = [];
135	            _allProperties = CollectAllProperties();
136	            _propertyLookup = _allProperties.ToDictionary(p => p.Property);
137	        }
138	
