3	
4	using Azure.Generator.Management.Models;
5	using Azure.Generator.Management.Providers;
6	using Azure.Generator.Management.Tests.Common;
7	using Azure.Generator.Management.Tests.TestHelpers;
8	using Microsoft.TypeSpec.Generator.Input;
9	using Microsoft.TypeSpec.Generator.Primitives;
10	using Microsoft.TypeSpec.Generator.Providers;
11	using NUnit.Framework;
12	using System.Text.Json;
13	using System.Text.Json.Serialization;
14	
15	namespace Azure.Generator.Management.Tests.Providers
16	{
17	    internal class OperationSourceProviderTests
18	    {
19	        [TestCase]
20	        public void Verify_MultipleResourcesSharingDataModel_GeneratesSeparateOperationSources()
21	        {
22	            // This test verifies the fix for the issue where multiple resources sharing the same data model
23	            // only generated one OperationSource, causing compilation errors.
24	
25	            // Create test data with two resources (Site and SitesBySubscription) sharing the same model (SiteData)
26	            const string sharedModelName = "SiteData";
27	            var sharedModel = InputFactory.Model(sharedModelName,
28	                usage: InputModelTypeUsage.Output | InputModelTypeUsage.Json,
29	                properties:
30	                [
31	                    InputFactory.Property("id", InputPrimitiveType.String, isReadOnly: true),
32	                    InputFactory.Property("name", InputPrimitiveType.String, isReadOnly: true),
33	                    InputFactory.Property("location", InputPrimitiveType.String, isReadOnly: false),
34	                ],
35	                decorators: []);
36	
37	            var responseType = InputFactory.OperationResponse(statusCodes: [200], bodytype: sharedModel);
38	            var uuidType = new InputPrimitiveType(InputPrimitiveTypeKind.String, "uuid", "Azure.Core.uuid");
39	
40	            // Common parameters
41	            var subsIdParameter = InputFactory.PathParameter("subscriptionId", uuidType, isRequired: true);
42	            var rgParameter = InputFactory.PathParameter("resourceGroupName", InputPrimitiveType.String, isRequired: true);
43	            var subscriptionIdMethodParam = InputFactory.MethodParameter("subscriptionId", uuidType, location: InputRequestLocation.Path);
44	            var resourceGroupMethodParam = InputFactory.MethodParameter("resourceGroupName", InputPrimitiveType.String, location: InputRequestLocation.Path);
45	
46	            // First resource: Site (resource group scoped)
47	            var siteNameParameter = InputFactory.PathParameter("siteName", InputPrimitiveType.String, isRequired: true);
48	            var siteNameMethodParam = InputFactory.MethodParameter("siteName", InputPrimitiveType.String, location: InputRequestLocation.Path);
49	
50	            var createSiteOperation = InputFactory.Operation(
51	                name: "createSite",
52	                responses: [responseType],
53	                parameters: [subsIdParameter, rgParameter, siteNameParameter],
54	                path: "/subscriptions/{subscriptionId}/resourceGroups/{resourceGroupName}/providers/Microsoft.SiteManager/sites/{siteName}");
55	
56	            var lroMetadata1 = InputFactory.LongRunningServiceMetadata(1, InputFactory.OperationResponse([200], sharedModel), null);
57	            var createSiteMethod = InputFactory.LongRunningServiceMethod(
58	                "createSite",
59	                createSiteOperation,
60	                parameters: [siteNameMethodParam, subscriptionIdMethodParam, resourceGroupMethodParam],
61	                longRunningServiceMetadata: lroMetadata1);
62	
63	            var getSiteOperation = InputFactory.Operation(
64	                name: "getSite",
65	                responses: [responseType],
66	                parameters: [siteNameMethodParam, subscriptionIdMethodParam, resourceGroupMethodParam]);
67	
68	            var getSiteMethod = InputFactory.BasicServiceMethod(
69	                "getSite",
70	                getSiteOperation);
71	
72	            var siteResourceIdPattern = "/subscriptions/{subscriptionId}/resourceGroups/{resourceGroupName}/providers/Microsoft.SiteManager/sites/{siteName}";
73	            var siteDecorator = BuildArmProviderSchema(
74	                sharedModel,
75	                [
76	                    new ResourceMethod(ResourceOperationKind.Create, createSiteMethod, new RequestPathPattern(createSiteOperation.Path), new ArmScopeInfo(ResourceScope.ResourceGroup, new RequestPathPattern(siteResourceIdPattern), null), null!),
77	                    new ResourceMethod(ResourceOperationKind.Read, getSiteMethod, new RequestPathPattern(createSiteOperation.Path), new ArmScopeInfo(ResourceScope.ResourceGroup, new RequestPathPattern(siteResourceIdPattern), null), null!)
78	                ],
79	                siteResourceIdPattern,
80	                "Microsoft.SiteManager/sites",
81	                null,
82	                ResourceScope.ResourceGroup,
83	                "Site");
84	
85	            // Second resource: SitesBySubscription (subscription scoped, sharing same SiteData model)
86	            var siteNameParameter2 = InputFactory.PathParameter("siteName", InputPrimitiveType.String, isRequired: true);
87	            var siteNameMethodParam2 = InputFactory.MethodParameter("siteName", InputPrimitiveType.String, location: InputRequestLocation.Path);
88	
89	            var createSiteBySubOperation = InputFactory.Operation(
90	                name: "createSitesBySubscription",
91	                responses: [responseType],
92	                parameters: [subsIdParameter, siteNameParameter2],
93	                path: "/subscriptions/{subscriptionId}/providers/Microsoft.SiteManager/sites/{siteName}");
94	
95	            var lroMetadata2 = InputFactory.LongRunningServiceMetadata(1, InputFactory.OperationResponse([200], sharedModel), null);
96	            var createSiteBySubMethod = InputFactory.LongRunningServiceMethod(
97	                "createSitesBySubscription",
98	                createSiteBySubOperation,
99	                parameters: [siteNameMethodParam2, subscriptionIdMethodParam],
100	                longRunningServiceMetadata: lroMetadata2);
101	
102	            var getSiteBySubOperation = InputFactory.Operation(
103	                name: "getSitesBySubscription",
104	                responses: [responseType],
105	                parameters: [siteNameMethodParam2, subscriptionIdMethodParam]);
106	
107	            var getSiteBySubMethod = InputFactory.BasicServiceMethod(
108	                "getSitesBySubscription",
109	                getSiteBySubOperation);
110	
111	            var sitesBySubscriptionResourceIdPattern = "/subscriptions/{subscriptionId}/providers/Microsoft.SiteManager/sites/{siteName}";
112	            var sitesBySubscriptionDecorator = BuildArmProviderSchema(
113	                sharedModel,
114	                [
115	                    new ResourceMethod(ResourceOperationKind.Create, createSiteBySubMethod, new RequestPathPattern(createSiteBySubOperation.Path), new ArmScopeInfo(ResourceScope.Subscription, new RequestPathPattern(sitesBySubscriptionResourceIdPattern), null), null!),
116	                    new ResourceMethod(ResourceOperationKind.Read, getSiteBySubMethod, new RequestPathPattern(createSiteBySubOperation.Path), new ArmScopeInfo(ResourceScope.Subscription, new RequestPathPattern(sitesBySubscriptionResourceIdPattern), null), null!)
117	                ],
