    {
        var decoratorProperty = typeof(InputModelType).GetProperty(nameof(InputModelType.Decorators));
        var setDecoratorMethod = decoratorProperty?.GetSetMethod(true);
        setDecoratorMethod!.Invoke(model, [decorators]);
    }
    return model;
}

