using Azure.Generator.Management.Models;
using Azure.Generator.Management.Tests.Common;
using Azure.Generator.Provisioning.Providers;
using Microsoft.TypeSpec.Generator.Input;
using NUnit.Framework;

namespace Azure.Generator.Provisioning.Tests;

public class SharedResourceModelTests
{
    [Test]
    public void SharedResourceModelCreatesDistinctResourceProviders()
    {
        var model = InputFactory.Model("SharedResource");
        var resourceGroupScope = new ArmScopeInfo(
            ResourceScope.ResourceGroup,
            new RequestPathPattern("/subscriptions/{subscriptionId}/resourceGroups/{resourceGroupName}"),
            null);
        var first = new ArmResourceMetadata(
            new RequestPathPattern("/subscriptions/{subscriptionId}/resourceGroups/{resourceGroupName}/providers/Test.Provider/first/{name}"),
            "FirstResource",
            "Test.Provider/first",
            model,
            resourceGroupScope,
            [],
            null,
            null,
            [],
            new ArmResourceNameConstraints(null, null, null),
            ["2024-01-01"],
            []);
        var second = first with
        {
            ResourceIdPattern = new RequestPathPattern("/subscriptions/{subscriptionId}/resourceGroups/{resourceGroupName}/providers/Test.Provider/second/{name}"),
            ResourceName = "SecondResource",
            ResourceType = "Test.Provider/second"
        };

        var firstProvider = new ProvisioningResourceProvider(model, first);
        var secondProvider = new ProvisioningResourceProvider(model, second);

        Assert.AreEqual("FirstResource", firstProvider.Name);
        Assert.AreEqual("SecondResource", secondProvider.Name);
        Assert.AreEqual("src/Generated/FirstResource.cs", firstProvider.RelativeFilePath.Replace('\\', '/'));
        Assert.AreEqual("src/Generated/SecondResource.cs", secondProvider.RelativeFilePath.Replace('\\', '/'));
    }
}

