using Azure.Generator.Management.Models;
using Azure.Generator.Management.Tests.Common;
using Azure.Generator.Provisioning.Providers;
using Microsoft.TypeSpec.Generator;
using Microsoft.TypeSpec.Generator.Input;
using Moq;
using System.Reflection;
using Microsoft.TypeSpec.Generator.Providers;
using NUnit.Framework;

namespace Azure.Generator.Provisioning.Tests;

public class SharedResourceModelTests
{
    [Test]
    public void SharedResourceModelCreatesDistinctResourceProviders()
    {
        var loadMethod = typeof(Configuration).GetMethod("Load", BindingFlags.Static | BindingFlags.NonPublic)!;
        var configuration = loadMethod.Invoke(null, [TestContext.CurrentContext.WorkDirectory, "{}"] )!;
        var context = new Mock<GeneratorContext>(configuration).Object;
        _ = new ProvisioningGenerator(context);
        var model = InputFactory.Model("SharedResource");
        var first = BuildResourceMetadata(model, "FirstResource", "Test.Provider/first");
        var second = BuildResourceMetadata(model, "SecondResource", "Test.Provider/second");

        Assert.AreEqual("FirstResource", InvokeBuildName(new ProvisioningResourceProvider(model, first)));
        Assert.AreEqual("SecondResource", InvokeBuildName(new ProvisioningResourceProvider(model, second)));
    }

    private static ArmResourceMetadata BuildResourceMetadata(InputModelType model, string resourceName, string resourceType)
        => new(
            new RequestPathPattern($"/subscriptions/{{subscriptionId}}/resourceGroups/{{resourceGroupName}}/providers/{resourceType}/{{name}}"),
            resourceName,
            resourceType,
            model,
            new ArmScopeInfo(
                ResourceScope.ResourceGroup,
                new RequestPathPattern("/subscriptions/{subscriptionId}/resourceGroups/{resourceGroupName}"),
                null),
            [],
            null,
            null,
            [],
            new ArmResourceNameConstraints(null, null, null),
            ["2024-01-01"],
            []);

    private static string InvokeBuildName(ModelProvider provider)
        => (string)typeof(ProvisioningResourceProvider)
            .GetMethod("BuildName", BindingFlags.Instance | BindingFlags.NonPublic)!
            .Invoke(provider, [])!;
}

